import{_ as s,o as i,c as a,a2 as t}from"./chunks/framework.Bk_3gXAz.js";const k=JSON.parse('{"title":"find-skills","description":"Helps users discover and install agent skills when they ask questions like \\"how do I do X\\", \\"find a skill for X\\", \\"is there a skill that can...\\", or express interest in extending capabilities. This skill should be used when the user is looking for functionality that might exist as an installable skill.","frontmatter":{"title":"find-skills","name":"find-skills","description":"Helps users discover and install agent skills when they ask questions like \\"how do I do X\\", \\"find a skill for X\\", \\"is there a skill that can...\\", or express interest in extending capabilities. This skill should be used when the user is looking for functionality that might exist as an installable skill."},"headers":[],"relativePath":"skills/find-skills.md","filePath":"skills/find-skills.md"}'),l={name:"skills/find-skills.md"};function n(o,e,r,d,p,h){return i(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="find-skills" tabindex="-1">Find Skills <a class="header-anchor" href="#find-skills" aria-label="Permalink to &quot;Find Skills&quot;">​</a></h1><p>This skill helps you discover and install skills from the open agent skills ecosystem.</p><h2 id="when-to-use-this-skill" tabindex="-1">When to Use This Skill <a class="header-anchor" href="#when-to-use-this-skill" aria-label="Permalink to &quot;When to Use This Skill&quot;">​</a></h2><p>Use this skill when the user:</p><ul><li>Asks &quot;how do I do X&quot; where X might be a common task with an existing skill</li><li>Says &quot;find a skill for X&quot; or &quot;is there a skill for X&quot;</li><li>Asks &quot;can you do X&quot; where X is a specialized capability</li><li>Expresses interest in extending agent capabilities</li><li>Wants to search for tools, templates, or workflows</li><li>Mentions they wish they had help with a specific domain (design, testing, deployment, etc.)</li></ul><h2 id="what-is-the-skills-cli" tabindex="-1">What is the Skills CLI? <a class="header-anchor" href="#what-is-the-skills-cli" aria-label="Permalink to &quot;What is the Skills CLI?&quot;">​</a></h2><p>The Skills CLI (<code>npx skills</code>) is the package manager for the open agent skills ecosystem. Skills are modular packages that extend agent capabilities with specialized knowledge, workflows, and tools.</p><p><strong>Key commands:</strong></p><ul><li><code>npx skills find [query]</code> - Search for skills interactively or by keyword</li><li><code>npx skills add &lt;package&gt;</code> - Install a skill from GitHub or other sources</li><li><code>npx skills check</code> - Check for skill updates</li><li><code>npx skills update</code> - Update all installed skills</li></ul><p><strong>Browse skills at:</strong> <a href="https://skills.sh/" target="_blank" rel="noreferrer">https://skills.sh/</a></p><h2 id="how-to-help-users-find-skills" tabindex="-1">How to Help Users Find Skills <a class="header-anchor" href="#how-to-help-users-find-skills" aria-label="Permalink to &quot;How to Help Users Find Skills&quot;">​</a></h2><h3 id="step-1-understand-what-they-need" tabindex="-1">Step 1: Understand What They Need <a class="header-anchor" href="#step-1-understand-what-they-need" aria-label="Permalink to &quot;Step 1: Understand What They Need&quot;">​</a></h3><p>When a user asks for help with something, identify:</p><ol><li>The domain (e.g., React, testing, design, deployment)</li><li>The specific task (e.g., writing tests, creating animations, reviewing PRs)</li><li>Whether this is a common enough task that a skill likely exists</li></ol><h3 id="step-2-check-the-leaderboard-first" tabindex="-1">Step 2: Check the Leaderboard First <a class="header-anchor" href="#step-2-check-the-leaderboard-first" aria-label="Permalink to &quot;Step 2: Check the Leaderboard First&quot;">​</a></h3><p>Before running a CLI search, check the <a href="https://skills.sh/" target="_blank" rel="noreferrer">skills.sh leaderboard</a> to see if a well-known skill already exists for the domain. The leaderboard ranks skills by total installs, surfacing the most popular and battle-tested options.</p><p>For example, top skills for web development include:</p><ul><li><code>vercel-labs/agent-skills</code> — React, Next.js, web design (100K+ installs each)</li><li><code>anthropics/skills</code> — Frontend design, document processing (100K+ installs)</li></ul><h3 id="step-3-search-for-skills" tabindex="-1">Step 3: Search for Skills <a class="header-anchor" href="#step-3-search-for-skills" aria-label="Permalink to &quot;Step 3: Search for Skills&quot;">​</a></h3><p>If the leaderboard doesn&#39;t cover the user&#39;s need, run the find command:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> find</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [query]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>For example:</p><ul><li>User asks &quot;how do I make my React app faster?&quot; → <code>npx skills find react performance</code></li><li>User asks &quot;can you help me with PR reviews?&quot; → <code>npx skills find pr review</code></li><li>User asks &quot;I need to create a changelog&quot; → <code>npx skills find changelog</code></li></ul><h3 id="step-4-verify-quality-before-recommending" tabindex="-1">Step 4: Verify Quality Before Recommending <a class="header-anchor" href="#step-4-verify-quality-before-recommending" aria-label="Permalink to &quot;Step 4: Verify Quality Before Recommending&quot;">​</a></h3><p><strong>Do not recommend a skill based solely on search results.</strong> Always verify:</p><ol><li><strong>Install count</strong> — Prefer skills with 1K+ installs. Be cautious with anything under 100.</li><li><strong>Source reputation</strong> — Official sources (<code>vercel-labs</code>, <code>anthropics</code>, <code>microsoft</code>) are more trustworthy than unknown authors.</li><li><strong>GitHub stars</strong> — Check the source repository. A skill from a repo with &lt;100 stars should be treated with skepticism.</li></ol><h3 id="step-5-present-options-to-the-user" tabindex="-1">Step 5: Present Options to the User <a class="header-anchor" href="#step-5-present-options-to-the-user" aria-label="Permalink to &quot;Step 5: Present Options to the User&quot;">​</a></h3><p>When you find relevant skills, present them to the user with:</p><ol><li>The skill name and what it does</li><li>The install count and source</li><li>The install command they can run</li><li>A link to learn more at skills.sh</li></ol><p>Example response:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I found a skill that might help! The &quot;react-best-practices&quot; skill provides</span></span>
<span class="line"><span>React and Next.js performance optimization guidelines from Vercel Engineering.</span></span>
<span class="line"><span>(185K installs)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>To install it:</span></span>
<span class="line"><span>npx skills add vercel-labs/agent-skills@react-best-practices</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Learn more: https://skills.sh/vercel-labs/agent-skills/react-best-practices</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="step-6-offer-to-install" tabindex="-1">Step 6: Offer to Install <a class="header-anchor" href="#step-6-offer-to-install" aria-label="Permalink to &quot;Step 6: Offer to Install&quot;">​</a></h3><p>If the user wants to proceed, you can install the skill for them:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">owner/repo@skil</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The <code>-g</code> flag installs globally (user-level) and <code>-y</code> skips confirmation prompts.</p><h2 id="common-skill-categories" tabindex="-1">Common Skill Categories <a class="header-anchor" href="#common-skill-categories" aria-label="Permalink to &quot;Common Skill Categories&quot;">​</a></h2><p>When searching, consider these common categories:</p><table tabindex="0"><thead><tr><th>Category</th><th>Example Queries</th></tr></thead><tbody><tr><td>Web Development</td><td>react, nextjs, typescript, css, tailwind</td></tr><tr><td>Testing</td><td>testing, jest, playwright, e2e</td></tr><tr><td>DevOps</td><td>deploy, docker, kubernetes, ci-cd</td></tr><tr><td>Documentation</td><td>docs, readme, changelog, api-docs</td></tr><tr><td>Code Quality</td><td>review, lint, refactor, best-practices</td></tr><tr><td>Design</td><td>ui, ux, design-system, accessibility</td></tr><tr><td>Productivity</td><td>workflow, automation, git</td></tr></tbody></table><h2 id="tips-for-effective-searches" tabindex="-1">Tips for Effective Searches <a class="header-anchor" href="#tips-for-effective-searches" aria-label="Permalink to &quot;Tips for Effective Searches&quot;">​</a></h2><ol><li><strong>Use specific keywords</strong>: &quot;react testing&quot; is better than just &quot;testing&quot;</li><li><strong>Try alternative terms</strong>: If &quot;deploy&quot; doesn&#39;t work, try &quot;deployment&quot; or &quot;ci-cd&quot;</li><li><strong>Check popular sources</strong>: Many skills come from <code>vercel-labs/agent-skills</code> or <code>ComposioHQ/awesome-claude-skills</code></li></ol><h2 id="when-no-skills-are-found" tabindex="-1">When No Skills Are Found <a class="header-anchor" href="#when-no-skills-are-found" aria-label="Permalink to &quot;When No Skills Are Found&quot;">​</a></h2><p>If no relevant skills exist:</p><ol><li>Acknowledge that no existing skill was found</li><li>Offer to help with the task directly using your general capabilities</li><li>Suggest the user could create their own skill with <code>npx skills init</code></li></ol><p>Example:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I searched for skills related to &quot;xyz&quot; but didn&#39;t find any matches.</span></span>
<span class="line"><span>I can still help you with this task directly! Would you like me to proceed?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>If this is something you do often, you could create your own skill:</span></span>
<span class="line"><span>npx skills init my-xyz-skill</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div>`,45)])])}const u=s(l,[["render",n]]);export{k as __pageData,u as default};
